FUNCTION FindKernel(A, m, n):
 // A is m×n matrix, solve Ax = 0

 // Apply Gaussian elimination to row echelon form
 R = RowEchelonForm(A)

 // Identify pivot and free variables
 pivots = FindPivots(R)
 free = FindFreeVariables(pivots, n)

 // Express solution in terms of free variables
 kernel_basis = []
 FOR each free_var f in free:
 // Set free variable to 1, others to 0
 solution = SolveForPivotVariables(R, f)
 kernel_basis.append(solution)

 RETURN kernel_basis

// Example: A = [[1,1,0],[0,1,1]]
kernel = FindKernel([[1,1,0],[0,1,1]], 2, 3)
